CREATE OR REPLACE FUNCTION fpa_tel_bakk_acc_no_dividend (as_memno char,as_gpay char) RETURNS varchar AS $body$
DECLARE

  ls_acc_no varchar(100);

BEGIN
  select  bank_acc_no into STRICT ls_acc_no
  from    sc_mem_m_member_bank_accno
  where (membership_no = as_memno)
  and (paid_dividen = '1');
  -- ใช้เคส เผื่อลูกค้าต้องการเพิ่ม
  case upper(trim(both as_gpay))
   when 'TRD' then
     ls_acc_no := 'ACC.'||ls_acc_no;
   else
    ls_acc_no := ls_acc_no;
  end case;
  return trim(both ls_acc_no);
exception
when no_data_found then return null;
when others then CALL spa_dberror('FPA_TEL_BAKK_ACC_NO_DIVIDEND');return null;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
